module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg dout_parallel,
    output reg dout_valid
);
    reg [3:0] cnt;
    reg [7:0] data;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 0;
            data <= 0;
            dout_parallel <= 0;
            dout_valid <= 0;
        end
        else begin
            if (din_valid) begin
                data[cnt] <= din_serial;
                cnt <= cnt + 1;
                if (cnt == 7) begin
                    dout_parallel <= data;
                    dout_valid <= 1;
                    cnt <= 0;
                    data <= 0;
                end
                else begin
                    dout_valid <= 0;
                end
            end
            else begin
                dout_valid <= 0;
            end
        end
    end
endmodule
